targets.query:
// Simplified: Cost / Heat = (Energy × Tariff) / (Energy × COP)
// = Tariff / COP
// Using average tariff
avg_tariff = (${regular_tariff} + ${low_tariff}) / 2.0

// Get COP 24h (placeholder - use actual from panel 2)
from(bucket: "homeassistant")
  |> range(start: -1d)
  |> filter(fn: (r) => r["entity_id"] =~ /aloha_sensory_aquatics/ and r["entity_id"] =~ /cumulative_power_consumption_z06/)
  |> filter(fn: (r) => r["_field"] == "value")
  |> aggregateWindow(every: 1d, fn: spread)
  |> map(fn: (r) => ({r with _value: avg_tariff / 3.5}))
  |> last()
